+func TestHasNerdFonts_ExplicitEnable(t *testing.T) {
+	t.Setenv("NTM_USE_ICONS", "1")
+	t.Setenv("NERD_FONTS", "")
+	if !HasNerdFonts() {
+		t.Error("expected true with NTM_USE_ICONS=1")
+	}
+}
